class Solution(object):
    def countMaxOrSubsets(self, nums):
        max_or = 0
        for num in nums:
            max_or |= num
        count = 0
        def backtrack(index, current_or):
            nonlocal count
            if current_or == max_or:
                count += 2**(len(nums) - index)
                return
            if index >= len(nums):
                return
            for i in range(index, len(nums)):
                backtrack(i + 1, current_or | nums[i])
        backtrack(0, 0)
        return count
